// 1. Gunakan sintaks baru untuk Static Data
const staticData = $getWorkflowStaticData('global');

if (!staticData.previousData) {
  staticData.previousData = {};
}

// 2. Ambil data input menggunakan $input.all()
//const inputItems = $input.all();
const inputItems = $('Get rows').all();


// Convert current data to object keyed by ID
const currentData = {};
for (const item of inputItems) {
  // Pastikan field 'ID' ada di data kamu
  if (item.json.ID) {
    currentData[item.json.ID] = item.json;
  }
}

const changes = [];

// Detect New and Updated rows
for (const id in currentData) {
  const currentRow = currentData[id];
  const previousRow = staticData.previousData[id];

  if (!previousRow) {  
    const newFields = [];

    for (const key in currentRow) {
      newFields.push({
        source: currentRow,
        field: key,
        old: null,
        new: currentRow[key]
      });
    }

    changes.push({
      type: "NEW",
      id,
      changes: newFields
    });
    continue;
  }

  const rowChanges = [];
  let hasChanged = false;
  const config = $input.first().json.CONFIG;

  for (const key in currentRow) {

    if (key === config.idField) continue;
    if (config.ignoreFields.includes(key)) continue;
    if (config.monitorOnly && !config.monitorOnly.includes(key)) continue;

    if (JSON.stringify(currentRow[key]) !== JSON.stringify(previousRow[key])) {
      rowChanges.push({
        source: currentRow,
        field: key,
        old: previousRow[key],
        new: currentRow[key]
      });
      hasChanged = true;
    }
  }

  if (hasChanged) {
    changes.push({
      type: "UPDATED",
      id,
      changes: rowChanges
    });
  }

}

// Detect Deleted rows
for (const id in staticData.previousData) {
  if (!currentData[id]) {
    changes.push({
      type: "DELETED",
      id
    });
  }
}

// 3. Simpan snapshot untuk run berikutnya
staticData.previousData = currentData;

// Kembalikan hasil sebagai array item n8n
return [{
  json: {
    hasChanges: changes.length > 0,
    totalChanges: changes.length,
    changes
  }
}];

let message = "📊 Excel Update Detected\n\n";
let sendMessage = false;
for (const change of $json.changes) {

  if (change.type === "NEW") {
    message += `🆕 New Row Added (ID: ${change.id})\n`;

    if (Array.isArray(change.changes)) {
      for (const fieldChange of change.changes) {
        message += `- ${fieldChange.field}: ${fieldChange.new}\n`;
      }
    }
    sendMessage=true;
    message += "\n";
  }

  if (change.type === "UPDATED") {
    message += `✏️ Row Updated (ID: ${change.id})\n`;

    if (Array.isArray(change.changes)) {
      for (const fieldChange of change.changes) {
        message += `- ${fieldChange.field}: ${fieldChange.old} → ${fieldChange.new}\n`;
      }
    }

    message += "\n";
    sendMessage=true;
  }

  if (change.type === "DELETED") {
    message += `❌ Row Deleted (ID: ${change.id})\n\n`;
    sendMessage=true;
  }
}

return [{
  json: {
    message,
    sendMessage
  }
}];

const auditRows = [];
for (const change of $json.changes) {
  if (change.type === "DELETED") {
    auditRows.push({
      Timestamp: new Date().toISOString(),
      ChangeType: "DELETED",
      RowID: change.id,
      Field: null,
      OldValue: null,
      NewValue: null
    });
    continue;
  }

  for (const fieldChange of change.changes) {
    auditRows.push({
      Timestamp: new Date().toISOString(),
      ChangeType: change.type,
      RowID: change.id,
      Field: fieldChange.field,
      OldValue: fieldChange.old ?? null,
      NewValue: fieldChange.new ?? null
    });
  }
}

return auditRows.map(r => ({ json: r }));

// check apakah ada yang waiting approval
let change_message = [];
for (const change of $json.changes) {
  for (const fieldChange of change.changes) {
    if(fieldChange.field=='Status' && fieldChange.new == 'Waiting Approval'){
      change_message.push(fieldChange.source); 
    }
  }
}

// Kembalikan setiap item di dalam 'changes' sebagai item n8n yang terpisah
return change_message.map(change => {
  return {
    // json: change
    json : change
  };
});
